// ═══════════════════════════════════════════════════════════════════════
// REPLACEMENT ENGINE
// ═══════════════════════════════════════════════════════════════════════

console.log(`Translation dictionary: ${Object.keys(T).length} entries\n`);

let grandTotal = 0;

for (const file of FILES) {
  const fp = path.join(BASE, file);
  if (!fs.existsSync(fp)) { console.log(`SKIP: ${file}`); continue; }

  let content = fs.readFileSync(fp, 'utf8');
  let count = 0;

  for (const [en, tr] of Object.entries(T)) {
    for (const q of ["'", '"']) {
      for (const [lang, val] of Object.entries(tr)) {
        const old = `${lang}: ${q}${en}${q}`;
        const rep = `${lang}: ${q}${val}${q}`;
        if (old !== rep && content.includes(old)) {
          const before = content.split(old).length - 1;
          content = content.split(old).join(rep);
          count += before;
        }
      }
    }
  }

  if (count > 0) fs.writeFileSync(fp, content, 'utf8');
  grandTotal += count;
  console.log(`${file}: ${count} replacements`);
}

console.log(`\nTotal: ${grandTotal} replacements`);

// Count remaining
console.log('\n--- Remaining seeded ---');
let totalRemaining = 0;
for (const file of FILES) {
  const fp = path.join(BASE, file);
  if (!fs.existsSync(fp)) continue;
  const content = fs.readFileSync(fp, 'utf8');
  const ta = (content.match(/ta: '[A-Z][^']*'/g) || []).length;
  const te = (content.match(/te: '[A-Z][^']*'/g) || []).length;
  const bn = (content.match(/bn: '[A-Z][^']*'/g) || []).length;
  const kn = (content.match(/kn: '[A-Z][^']*'/g) || []).length;
  const gu = (content.match(/gu: '[A-Z][^']*'/g) || []).length;
  const sum = ta+te+bn+kn+gu;
  totalRemaining += sum;
  if (sum > 0) {
    console.log(`${file}: ${sum} (ta:${ta} te:${te} bn:${bn} kn:${kn} gu:${gu})`);
    // Show first remaining
    const m = content.match(/ta: '([A-Z][^']*)'/);
    if (m) console.log(`  Sample: ${m[1].substring(0,80)}`);
  }
}
console.log(`\nTotal remaining: ${totalRemaining}`);
